const queries = [
  // === INDIE HACKERS — High Priority ===
  { q: 'site:indiehackers.com "looking for" OR "need help" OR "hire" "developer" OR "agency" OR "software" OR "AI" OR "automation"', platform: 'indiehackers', priority: 'high' },
  { q: 'site:indiehackers.com "outsource" OR "dev shop" OR "dev agency" OR "development company" "build" OR "product" OR "SaaS"', platform: 'indiehackers', priority: 'high' },
  { q: 'site:indiehackers.com "building" OR "built" "AI" OR "automation" OR "SaaS" OR "software" "need" OR "help" OR "anyone"', platform: 'indiehackers', priority: 'high' },
  { q: 'site:indiehackers.com "raise" OR "raised" OR "funded" "AI" OR "software" OR "automation" "build" OR "team" OR "hire" 2025', platform: 'indiehackers', priority: 'high' },

  // === PRODUCT HUNT DISCUSSIONS — Medium Priority ===
  { q: 'site:producthunt.com/discussions "build" OR "hire" OR "looking for" "developer" OR "agency" OR "AI" OR "automation"', platform: 'producthunt', priority: 'medium' },
  { q: 'site:producthunt.com/discussions "software" OR "SaaS" OR "automation" "need" OR "want" OR "help" OR "recommend"', platform: 'producthunt', priority: 'medium' },
  { q: 'site:producthunt.com/discussions "AI" OR "machine learning" OR "LLM" "build" OR "integrate" OR "implement" "startup" OR "company"', platform: 'producthunt', priority: 'medium' },

  // === BETALIST — Medium Priority ===
  { q: 'site:betalist.com "AI" OR "automation" OR "SaaS" OR "machine learning" "startup" OR "launch" OR "build"', platform: 'betalist', priority: 'medium' },
  { q: 'site:betalist.com "software" OR "platform" OR "tool" "enterprise" OR "business" OR "workflow" 2025', platform: 'betalist', priority: 'medium' },

  // === WELLFOUND / ANGELLIST — Medium Priority ===
  { q: 'site:wellfound.com/jobs "contract" OR "freelance" "AI" OR "machine learning" OR "automation" OR "software engineer"', platform: 'wellfound', priority: 'medium' },
  { q: 'site:wellfound.com/company "AI" OR "automation" OR "SaaS" "seed" OR "series a" "hiring" OR "contract" 2025', platform: 'wellfound', priority: 'medium' },
  { q: 'site:wellfound.com "AI development" OR "ML engineer" OR "automation engineer" "contract" OR "part-time" OR "consulting"', platform: 'wellfound', priority: 'medium' },

  // === F6S — Low Priority ===
  { q: 'site:f6s.com "AI" OR "machine learning" OR "automation" OR "software development" startup 2025', platform: 'f6s', priority: 'low' },
  { q: 'site:f6s.com "looking for" OR "need" "developer" OR "agency" OR "tech partner" OR "co-founder"', platform: 'f6s', priority: 'low' },

  // === MICROCONF — Low Priority ===
  { q: 'site:microconf.com "build" OR "hire" OR "agency" OR "developer" "SaaS" OR "software" OR "automation"', platform: 'microconf', priority: 'low' },
  { q: '"microconf" "looking for" OR "hire" OR "outsource" "developer" OR "AI" OR "software" site:community.microconf.com OR site:microconf.com', platform: 'microconf', priority: 'low' },

  // === HACKERNOON — Low Priority ===
  { q: 'site:hackernoon.com "AI" OR "automation" OR "SaaS" "build" OR "startup" OR "founder" "2025"', platform: 'hackernoon', priority: 'low' },
  { q: 'site:hackernoon.com "machine learning" OR "computer vision" OR "data pipeline" "company" OR "startup" OR "product" 2025', platform: 'hackernoon', priority: 'low' }
];
return queries.map(q => ({ json: q }));

const skipKeywords = [
  'for hire', 'i am available', 'available for work', 'hire me',
  'my portfolio', 'i offer services', 'i specialize in', 'i will build',
  'seeking employment', 'looking for work', 'open to opportunities',
  'logo design', 'seo services', 'social media manager', 'content writer',
  'virtual assistant', 'data entry', 'graphic designer', 'video editor',
  'job listing', 'full-time position', 'apply now'
];

const platformMap = {
  'indiehackers.com': 'indiehackers',
  'producthunt.com': 'producthunt',
  'betalist.com': 'betalist',
  'wellfound.com': 'wellfound',
  'angel.co': 'wellfound',
  'f6s.com': 'f6s',
  'microconf.com': 'microconf',
  'hackernoon.com': 'hackernoon'
};

const priorityMap = {
  'indiehackers': 'high',
  'producthunt': 'medium',
  'betalist': 'medium',
  'wellfound': 'medium',
  'f6s': 'low',
  'microconf': 'low',
  'hackernoon': 'low'
};

const budgetPatterns = [
  /([\$€£][\d,]+(?:,\d{3})*(?:k)?(?:\s[-–]\s*[\$€£]?[\d,]+(?:k)?)?(?:\s*(?:USD|EUR|GBP))?)/i,
  /(\d+[kK]\s*[-–]\s*\d+[kK])/,
  /budget[:\s]+([\$€£][\d,k.]+[\s\w-]*)/i
];

const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const searchQ = data.search_parameters?.q || '';
  const organicResults = data.organic_results || [];

  // Detect platform from query
  let platform = 'unknown';
  for (const [domain, pname] of Object.entries(platformMap)) {
    if (searchQ.includes(domain) || searchQ.includes(pname)) { platform = pname; break; }
  }

  for (const r of organicResults) {
    const link = r.link || '';
    if (!link) continue;

    // Detect platform from actual URL
    let actualPlatform = platform;
    if (actualPlatform === 'unknown') {
      for (const [domain, pname] of Object.entries(platformMap)) {
        if (link.includes(domain)) { actualPlatform = pname; break; }
      }
    }
    if (actualPlatform === 'unknown') continue;

    // Skip Wellfound company-directory and profile pages (not job listings)
    if (actualPlatform === 'wellfound' && !link.includes('/jobs') && !link.includes('/company') && !link.includes('/l/')) continue;

    const id = actualPlatform + '_' + link.replace(/[^a-z0-9]/gi, '').slice(-70);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (skipKeywords.some(kw => fullText.includes(kw))) continue;

    // Extract budget
    let budget_text = '';
    for (const pat of budgetPatterns) {
      const m = (snippet + ' ' + title).match(pat);
      if (m) { budget_text = (m[1] || m[0]).trim().substring(0, 80); break; }
    }

    results.push({ json: {
      title,
      description: snippet,
      source: actualPlatform,
      source_url: link,
      source_id: id,
      posted_at: (() => { try { const d = r.date ? new Date(r.date) : null; return (d && !isNaN(d)) ? d.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: '',
      subreddit: actualPlatform,
      upvotes: 0,
      num_comments: 0,
      flair_text: priorityMap[actualPlatform] || 'low',
      budget_text,
      platform: actualPlatform
    }});
  }
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'startup-communities' } }];
// Cap at 30 leads per run
return results.slice(0, 30);

const post = $input.item.json;
if (post._empty || post._noData) return { json: post };

const apiKey = $env.GOOGLE_AI_API_KEY;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, custom software, data pipelines.

These leads come from STARTUP & FOUNDER COMMUNITIES — Indie Hackers, Product Hunt, BetaList, Wellfound, F6S, MicroConf, HackerNoon. These are founders, indie hackers, and builders who may be actively seeking a dev partner, agency, or AI implementation help.

PLATFORM CONTEXT:
- Indie Hackers: Solo founders/bootstrappers building products. High signal if they mention needing dev help or AI.
- Product Hunt: Early-stage product launchers. Good signal if discussing tech stack or build needs.
- BetaList: Pre-launch startups. Good signal if AI/automation is core to their product.
- Wellfound: Contract/freelance job postings from funded startups. HIGH signal — these are active hiring needs.
- F6S: Startup applications and profiles. Medium signal.
- MicroConf: Bootstrapped SaaS community. High relevance if asking for dev help.
- HackerNoon: Tech articles. Lower signal unless describing a build need.

IDEAL LEAD: A founder, CTO, or decision-maker actively seeking a dev partner, AI implementation, or building a product that needs custom software.

HARD EXCLUSIONS — Score overall_score 0.0 immediately, do not process:
- Lead is from India or an Indian company (location: India, .in domain, Indian city/company name context) → 0.0
- Lead is requesting to build a SaaS subscription product (we do NOT build SaaS products) → 0.0  
- Budget is clearly under $10,000 OR budget_score would be below 0.3 → 0.0
- Individual freelancer or [For Hire] ad → 0.0

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 1.0=Wellfound contract job for AI/ML/automation | 0.9=founder explicitly seeking dev agency/partner | 0.8=building AI/SaaS product and needs tech help | 0.7=startup that raised and needs to build fast | 0.5=general startup content with AI context | 0.2=blog/article, no buyer signal | 0.0=irrelevant
2. budget_score: 1.0=Wellfound contract with $50K+ scope | 0.8=funded startup ($1M+) | 0.7=bootstrapper with revenue | 0.6=pre-revenue but strong signals | 0.5=unknown, startup context | 0.3=solo hobbyist | 0.1=student project
3. urgency_score: 1.0=active job posting/contract this week | 0.8=founder actively deciding, recent post | 0.6=product launching soon | 0.4=exploring options | 0.2=ideation stage | 0.1=archived/old
4. win_probability: 0.9=contract posting explicitly for AI/ML agency | 0.8=founder asking for agency recommendation | 0.7=bootstrapper needing custom dev | 0.5=startup with ambiguous need | 0.3=likely wants solo freelancer | 0.1=no fit

BUDGET ESTIMATION (ALWAYS fill estimated_budget_text, never null):
- Wellfound contract posting → "$15K-$100K (contract scope)"
- Funded startup (Seed/Series A) → "$25K-$200K (startup build budget)"
- Bootstrapped with revenue → "$10K-$75K (bootstrapper scope)"
- Pre-revenue idea stage → "$5K-$30K (MVP scope)"
- Unknown startup context → "$10K-$75K (estimated startup scope)"

COMPANY EXTRACTION: Extract company name, founder name, website from snippet/URL/title. Never invent. Return null if not found.`;

const prompt = SYSTEM_PROMPT + `\n\nScore this startup community lead. Return ONLY a single valid JSON object:\n{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"summary":"2-4 sentence summary: who this is, what they are building or seeking, and why ScaleBuild AI is or isn't a fit","industry":"FinTech/HealthTech/SaaS/AI/Manufacturing/eCommerce/General","tags":["tag1","tag2"],"reasoning":"Explain each score — why relevance (buyer or not?), why budget (what signals exist?), why urgency (how active?), why win probability (agency fit?). Recommend: pursue or skip, and the best outreach angle.","estimated_budget_text":"$X-$Y (reason)","tech_stack":[],"company_name":null,"lead_founder_name":null,"lead_website":null}\n\nTitle: ${post.title}\nPlatform: ${post.source}\nPriority: ${post.flair_text}\nDescription: ${(post.description||'').substring(0, 1200)}${post.budget_text ? '\nBudget Signal: ' + post.budget_text : ''}`;

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 100000, temperature: 0.2, responseMimeType: 'application/json' }
};

let s = null;
try {
  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
    body
  });
  const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
  const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) s = JSON.parse(match[0]);
} catch(e) {}

if (!s) s = {
  relevance_score:0.3, budget_score:0.4, urgency_score:0.3, win_probability:0.3,
  summary:'Parse error - using defaults', industry:'General', tags:[], reasoning:'Could not parse Gemini response',
  estimated_budget_text:'$10K-$75K (estimated startup scope)', tech_stack:[],
  company_name:null, lead_founder_name:null, lead_website:null
};

const overall = Math.round(((s.relevance_score*0.35)+(s.budget_score*0.30)+(s.urgency_score*0.15)+(s.win_probability*0.20))*100)/100;
const alert_tier = overall>=0.85?'instant':overall>=0.70?'digest':overall>=0.30?'dashboard':'discard';

return { json: {
  source_id: post.source_id, title: post.title, description: post.description,
  source: post.source, source_url: post.source_url, posted_at: post.posted_at,
  author: post.author||'', subreddit: post.subreddit||post.source||'',
  upvotes: 0, num_comments: 0, flair_text: post.flair_text||'startup',
  relevance_score: s.relevance_score, budget_score: s.budget_score,
  urgency_score: s.urgency_score, win_probability: s.win_probability,
  overall_score: overall, ai_summary: s.summary, industry: s.industry,
  ai_tags: s.tags||[], ai_reasoning: s.reasoning,
  estimated_budget_text: s.estimated_budget_text||'',
  budget_mentioned: post.budget_text || s.estimated_budget_text || '',
  tech_stack: s.tech_stack||[], company_name: s.company_name||null,
  lead_founder: s.lead_founder_name||null, lead_company: s.company_name||null,
  lead_website: s.lead_website||null, lead_contact: null,
  lead_score: Math.round(overall*10),
  alert_tier, discovered_at: new Date().toISOString(), status:'new',
  location: s.location||null, deadline_text: null,
  outreach_draft: '',
  hunter_name:'', hunter_email:'', hunter_title:'', hunter_company:'',
  hunter_all_emails:'', hunter_all_names:'', hunter_all_titles:''
}};

const hunterResp = $input.item.json;
const original = $('Check - Has Lead Info').item.json;
const data = hunterResp?.data || {};
const emails = data.emails || [];
const org = data.organization || original.lead_company || '';

if (emails.length === 0) {
  return [{ json: { ...original, hunter_name: '', hunter_email: '', hunter_title: '', hunter_company: org, hunter_all_emails: '', hunter_all_names: '', hunter_all_titles: '' } }];
}

const priority = ['ceo','founder','co-founder','cto','owner','president','vp','director'];
const best = emails.find(e => priority.some(t => (e.position||'').toLowerCase().includes(t))) || emails[0];

const allEmails  = emails.map(e => e.value || '').filter(Boolean).join(', ');
const allNames   = emails.map(e => (e.first_name||e.last_name) ? `${e.first_name||''} ${e.last_name||''}`.trim() : '').filter(Boolean).join(', ');
const allTitles  = emails.map(e => e.position || '').filter(Boolean).join(', ');

return [{ json: {
  ...original,
  hunter_name:       best.first_name || best.last_name ? `${best.first_name||''} ${best.last_name||''}`.trim() : '',
  hunter_email:      best.value || '',
  hunter_title:      best.position || '',
  hunter_company:    org,
  hunter_all_emails: allEmails,
  hunter_all_names:  allNames,
  hunter_all_titles: allTitles
}}];

const seen = new Map();
for (const item of $input.all()) {
  const id = item.json.source_id;
  if (!id) continue;
  if (!seen.has(id)) {
    seen.set(id, item.json);
  } else {
    if (item.json.hunter_email && !seen.get(id).hunter_email) {
      seen.set(id, item.json);
    }
  }
}
return [...seen.values()]
  .sort((a, b) => (b.overall_score||0) - (a.overall_score||0))
  .map(json => ({ json }));
